ValidationRule.errorConditionFormula:
AND(
     NOT( $Permission.C_PERM_8030_Bypass_OwnedByCompany_V_RULE )
    ,AND( LEFT( OwnerId , 3)='005' 
         ,Owner:User.License_type__c !='Partner Community'
        )
    ,ISCHANGED(OwnerId)
    ,Employee_Email__c = null
    ,OR(
        NOT(CONTAINS('AES,LSDX', TEXT($User.Owned_by_Company__c)))
       ,AND( CONTAINS('AES,LSDX', TEXT($User.Owned_by_Company__c) )
            ,OR( AND( LEFT(OwnerId,3)='005'
                ,TEXT($User.Owned_by_Company__c)!= TEXT(Owner:User.Owned_by_Company__c)
                   )
                ,AND( LEFT(OwnerId,3)='00G'
                   ,NOT(CONTAINS(Owner:Queue.Name, TEXT(Owner:User.Owned_by_Company__c) ))
                  )
               )
            )
        )
    )
